#!/usr/bin/env bash
# workflow-3.sh — 注射操作执行（安全核心） SOP walkthrough for 医疗美容.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="医疗美容"
WORKFLOW="注射操作执行（安全核心）"

usage() {
  cat <<EOF
workflow-3.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./workflow-3.sh             # interactive
  ./workflow-3.sh --dry-run
  ./workflow-3.sh --json
  ./workflow-3.sh --explain
  ./workflow-3.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "注射操作执行（安全核心）" 工作流。

一句话: 从「知情同意完成、准备进针」到「在正确层次、用安全剂量、避开危险区、把材料精确放到目标位置」的注射结果——这一行最高 tacit、安全红线最硬的环节。

入门 SOP 共 5 步, 失败模式自检 3 项。

相关心智模型:
  • 医美的第一性是医疗，不是消费: 医疗美容首先是外科与皮肤科的**医疗行为**（可致盲、致残、致死），不是快消品；任何决策的第一约束是安全与合规，不是美学最大化或转化率。
  • 先安全后审美：风险分层判断: 资深人的核心能力不是「打得漂亮」，而是**在安全处提效、在危险处零妥协**——知道哪一步能省、哪一步一步都不能省。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**无菌准备**：消毒、铺巾、器械无菌；急救设备就位（**机构须现场常备透明质酸酶 + 肾上腺素 + 氧气**）。 evidence: [T03-S007]"
  "**危险区识别 + 层次确认**：按面部危险区解剖（眉间/前额、鼻、鼻唇、颞、眶下、唇、颏与眼动脉系统吻合）标记避险，确认目标注射层次（皮内/真皮/皮下/骨膜上）。 evidence: [T03-S006]"
  "**避险手法三件套**：危险区优选钝针、推药前回抽确认未入血管、缓慢推注 + 单点限量（宁少勿多、宁慢勿快）。 evidence: [T03-S004, T03-S006, T03-S007]"
  "**剂量分配 + 边注边评**：按方案分点给量，边注射边观察皮肤颜色/求美者疼痛（剧痛/苍白=栓塞预警）。 evidence: [T03-S008]"
  "**肉毒点位与剂量**（如涉及）：按肌肉解剖定点位、按 U 控量，避免扩散到非目标肌（如上睑下垂、面具脸）。 evidence: [T03-S009]"
)
declare -a FAILURE_MODES=(
  "**危险区不回抽/快推大团注**：栓塞头号成因。actionable—危险三角/鼻/颞区一律钝针+回抽+缓慢推注+单点限量，绝不图快。"
  "**机构不备溶解酶/不会急救**：actionable—进操作台前确认透明质酸酶/肾上腺素/氧气在手边；不备=不应开展高危注射。"
  "**高危区不上超声硬打**：actionable—鼻/修复/颞等高危区，没有超声 mapping 能力就转诊有能力的医生，不要赌。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "workflow-3-walkthrough"
fi
